// Strategy base class (duck-typed in JS)
class ShippingStrategy {
  calculate(order) {
    throw new Error('calculate() must be implemented');
  }
}

class StandardShipping extends ShippingStrategy {
  calculate({ weight }) {
    return weight * 1.5;
  }
}

class ExpressShipping extends ShippingStrategy {
  calculate({ weight }) {
    return weight * 3.0 + 10;
  }
}

class OvernightShipping extends ShippingStrategy {
  calculate({ weight }) {
    return weight * 5.0 + 25;
  }
}

// Context
class ShoppingCart {
  #strategy;

  constructor(strategy) {
    this.#strategy = strategy;
  }

  setStrategy(strategy) {
    this.#strategy = strategy;
  }

  getShippingCost(order) {
    return this.#strategy.calculate(order);
  }
}

// Usage
const cart = new ShoppingCart(new StandardShipping());
const order = { weight: 10, destination: 'NYC' };

console.log(cart.getShippingCost(order)); // 15

cart.setStrategy(new ExpressShipping());
console.log(cart.getShippingCost(order)); // 40

cart.setStrategy(new OvernightShipping());
console.log(cart.getShippingCost(order)); // 75

