from __future__ import annotations
from abc import ABC, abstractmethod
from dataclasses import dataclass


@dataclass
class OrderData:
    weight: float
    destination: str


class ShippingStrategy(ABC):
    @abstractmethod
    def calculate(self, order: OrderData) -> float:
        ...


class StandardShipping(ShippingStrategy):
    def calculate(self, order: OrderData) -> float:
        return order.weight * 1.5


class ExpressShipping(ShippingStrategy):
    def calculate(self, order: OrderData) -> float:
        return order.weight * 3.0 + 10


class OvernightShipping(ShippingStrategy):
    def calculate(self, order: OrderData) -> float:
        return order.weight * 5.0 + 25


# Context
class ShoppingCart:
    def __init__(self, strategy: ShippingStrategy) -> None:
        self._strategy = strategy

    def set_strategy(self, strategy: ShippingStrategy) -> None:
        self._strategy = strategy

    def get_shipping_cost(self, order: OrderData) -> float:
        return self._strategy.calculate(order)


# Usage
cart = ShoppingCart(StandardShipping())
order = OrderData(weight=10, destination='NYC')

print(cart.get_shipping_cost(order))  # 15.0

cart.set_strategy(ExpressShipping())
print(cart.get_shipping_cost(order))  # 40.0

cart.set_strategy(OvernightShipping())
print(cart.get_shipping_cost(order))  # 75.0
